#include<iostream>
#include<cstdio>
using namespace std;
const int N = 250, K = 50;
int f[N][K];
int main() {
    int n, x, ans = 0;
    cin >> n;
    for(int i = 1;i <= n; i++) {
        cin >> x;
        f[i][x] = i + 1;
        ans = max(ans, x);
    }
    for(int k = 1;k <= 47; k++)
        for(int i = 1; i <= n; i++) {
            if (f[i][k] == 0) 
                f[i][k] = f[f[i][k - 1]][k - 1];
            if (f[i][k]) 
                ans = max (ans, k);
        }
    cout << ans << '\n';
    return 0;
}
